#!/bin/bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-27

# Integration test for scripts/cc-consolidate-milestones.sh — the idempotent
# sweep that collapses per-version "CC X.Y.Z adoption" milestones into the
# single "CC adoption" umbrella (Step 3b of claude-release-watch.yml).
#
# Mocks `gh` via PATH-shadow so cases run with no GitHub API access. Each
# case sets canned milestone/issue data via env, invokes the script, and
# asserts on the recorded MOCK_LOG (one line per gh invocation).
#
# Cases:
#   1. steady state (umbrella + a graduated M-bundle only) → no-op, 0 mutations
#   2. two stray per-version milestones → moves their issues, closes both
#   3. DRY_RUN=1 → zero actual mutations recorded
#   4. umbrella missing → creates it (POST)

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"

RED='\033[0;31m'
GREEN='\033[0;32m'
NC='\033[0m'

PASS=0
FAIL=0
log_pass() { echo -e "  ${GREEN}✓${NC} $1"; PASS=$((PASS + 1)); }
log_fail() { echo -e "  ${RED}✗${NC} $1 — $2"; FAIL=$((FAIL + 1)); }

# Count lines in MOCK_LOG matching an ERE. 0 when file missing/empty. silent: known-noise
count_calls() {
  local pattern="$1"
  if [ ! -s "$MOCK_LOG" ]; then echo 0; return; fi
  local n
  n=$(grep -cE "${pattern}" "$MOCK_LOG" 2>/dev/null) || n=0  # silent: known-noise
  echo "$n"
}

echo "CC Consolidate Milestones — sweep tests"
echo "========================================================="

# ---- mock gh (PATH-shadow) ----------------------------------------------------
MOCK_DIR=$(mktemp -d)
MOCK_LOG="$MOCK_DIR/gh.log"
export MOCK_LOG
cat > "$MOCK_DIR/gh" <<'MOCK'
#!/usr/bin/env bash
# Minimal gh mock for cc-consolidate-milestones.sh. Records every call as a
# space-joined line to MOCK_LOG, returns deterministic stubs driven by env:
#   MOCK_UMBRELLA_NUM   number returned for the umbrella resolve (empty → create)
#   MOCK_MILESTONES_TSV "<num>\t<title>" lines for the milestone-list call
#   MOCK_ISSUES         space-separated issue numbers `issue list` returns
set -euo pipefail
printf '%s\n' "$*" >> "$MOCK_LOG"

# Robustly find the REST URL (first arg starting with repos/).
URL=""
for a in "$@"; do
  if [[ "$a" == repos/* ]]; then URL="$a"; break; fi
done
# Find -X method and --jq filter.
METHOD=""; JQF=""
args=("$@")
for ((i = 0; i < ${#args[@]}; i++)); do
  [ "${args[i]}" = "-X" ] && METHOD="${args[i + 1]:-}"
  [ "${args[i]}" = "--jq" ] && JQF="${args[i + 1]:-}"
done

case "$1" in
  api)
    # Create umbrella.
    if [ "$METHOD" = "POST" ] && [[ "$URL" == *"/milestones" ]]; then
      echo "777"; exit 0
    fi
    # Reassign an issue's milestone.
    if [ "$METHOD" = "PATCH" ] && [[ "$URL" == *"/issues/"* ]]; then
      exit 0
    fi
    # Close a milestone.
    if [ "$METHOD" = "PATCH" ] && [[ "$URL" == *"/milestones/"* ]]; then
      exit 0
    fi
    # GET single milestone → open_issues (always emptied in this mock).
    if [[ "$URL" == *"/milestones/"* ]] && [[ "$URL" != *"?state="* ]]; then
      echo "0"; exit 0
    fi
    # GET milestone list — resolve umbrella vs enumerate.
    if [[ "$URL" == *"/milestones?state=open"* ]]; then
      if [[ "$JQF" == *"select(.title=="* ]]; then
        echo "${MOCK_UMBRELLA_NUM:-}"
      else
        printf '%s\n' "${MOCK_MILESTONES_TSV:-}"
      fi
      exit 0
    fi
    ;;
  issue)
    if [ "$2" = "list" ]; then
      for n in ${MOCK_ISSUES:-}; do echo "$n"; done
      exit 0
    fi
    ;;
esac
echo "MOCK_GH unhandled: $*" >&2
exit 1
MOCK
chmod +x "$MOCK_DIR/gh"
export PATH="$MOCK_DIR:$PATH"

cleanup() { rm -rf "$MOCK_DIR"; }
trap cleanup EXIT

if [ "$(command -v gh)" != "$MOCK_DIR/gh" ]; then
  echo "FATAL: mock gh not on PATH (got $(command -v gh || echo none))"
  exit 1
fi

SCRIPT="$PROJECT_ROOT/scripts/cc-consolidate-milestones.sh"
PATCH_ISSUE_RE='^api -X PATCH repos/[^ ]+/issues/'
CLOSE_RE='^api -X PATCH repos/[^ ]+/milestones/[0-9]+ -f state=closed'
POST_RE='^api -X POST repos/[^ ]+/milestones'

# TSV with real tabs. Umbrella (#10) + two strays + a graduated M-bundle (#13).
TWO_STRAYS=$(printf '10\tCC adoption\n11\tCC 2.1.140 adoption\n12\tCC 2.1.145 adoption\n13\tM146 — CC 2.1.143 hardening')
NO_STRAYS=$(printf '10\tCC adoption\n13\tM146 — CC 2.1.143 hardening')

# ============================================================================
# Case 1: steady state → no stray milestones → no-op
# ============================================================================
: > "$MOCK_LOG"
EXIT=0
MOCK_UMBRELLA_NUM=10 MOCK_MILESTONES_TSV="$NO_STRAYS" MOCK_ISSUES="1001 1002" \
  GH_REPO="acme/orchestkit" bash "$SCRIPT" >/tmp/consol-1.out 2>&1 || EXIT=$?
if [ "$EXIT" = "0" ] && grep -q "nothing to do" /tmp/consol-1.out; then
  log_pass "steady state: exits 0 with 'nothing to do'"
else
  log_fail "steady state" "exit=$EXIT (see /tmp/consol-1.out)"
fi
if [ "$(count_calls "$PATCH_ISSUE_RE")" = "0" ] && [ "$(count_calls "$CLOSE_RE")" = "0" ]; then
  log_pass "steady state: zero mutations"
else
  log_fail "steady state mutations" "expected 0 patch/close calls"
fi

# ============================================================================
# Case 2: two strays, each with 2 issues → 4 moves, 2 closes
# ============================================================================
: > "$MOCK_LOG"
EXIT=0
MOCK_UMBRELLA_NUM=10 MOCK_MILESTONES_TSV="$TWO_STRAYS" MOCK_ISSUES="1001 1002" \
  SLEEP_BETWEEN=0 GH_REPO="acme/orchestkit" bash "$SCRIPT" >/tmp/consol-2.out 2>&1 || EXIT=$?
MOVES=$(count_calls "$PATCH_ISSUE_RE")
CLOSES=$(count_calls "$CLOSE_RE")
if [ "$EXIT" = "0" ] && [ "$MOVES" = "4" ]; then
  log_pass "sweep: moved 4 issues (2 strays × 2 issues)"
else
  log_fail "sweep moves" "expected 4, got $MOVES (exit=$EXIT, see /tmp/consol-2.out)"
fi
if [ "$CLOSES" = "2" ]; then
  log_pass "sweep: closed 2 emptied milestones"
else
  log_fail "sweep closes" "expected 2, got $CLOSES"
fi
# The graduated M146 bundle must NOT be swept or closed.
if ! grep -q "M146" /tmp/consol-2.out; then
  log_pass "sweep: graduated M146 bundle left untouched"
else
  log_fail "sweep graduation" "M146 bundle should not appear in sweep output"
fi

# ============================================================================
# Case 3: DRY_RUN=1 → zero actual mutations
# ============================================================================
: > "$MOCK_LOG"
EXIT=0
DRY_RUN=1 MOCK_UMBRELLA_NUM=10 MOCK_MILESTONES_TSV="$TWO_STRAYS" MOCK_ISSUES="1001 1002" \
  GH_REPO="acme/orchestkit" bash "$SCRIPT" >/tmp/consol-3.out 2>&1 || EXIT=$?
if [ "$EXIT" = "0" ] \
  && [ "$(count_calls "$PATCH_ISSUE_RE")" = "0" ] \
  && [ "$(count_calls "$CLOSE_RE")" = "0" ] \
  && grep -q "DRY_RUN: would move" /tmp/consol-3.out; then
  log_pass "DRY_RUN: prints intent, performs zero mutations"
else
  log_fail "DRY_RUN" "expected 0 mutations + 'would move' notes (see /tmp/consol-3.out)"
fi

# ============================================================================
# Case 4: umbrella missing → creates it
# ============================================================================
: > "$MOCK_LOG"
EXIT=0
MOCK_UMBRELLA_NUM="" MOCK_MILESTONES_TSV="$NO_STRAYS" MOCK_ISSUES="" \
  GH_REPO="acme/orchestkit" bash "$SCRIPT" >/tmp/consol-4.out 2>&1 || EXIT=$?
if [ "$EXIT" = "0" ] && [ "$(count_calls "$POST_RE")" = "1" ]; then
  log_pass "umbrella missing: created via POST"
else
  log_fail "umbrella create" "expected 1 POST, got $(count_calls "$POST_RE") (see /tmp/consol-4.out)"
fi

echo "========================================================="
echo -e "Passed: ${GREEN}${PASS}${NC}  Failed: ${RED}${FAIL}${NC}"
[ "$FAIL" -eq 0 ]
